class Solution {
    void rev(vector<int>& a, int lo, int hi) {
        while (lo < hi) swap(a[lo++], a[hi--]);
    }
public:
    void rotate(vector<int>& nums, int k) {
        int n = nums.size();
        k %= n;
        rev(nums, 0, n - 1);
        rev(nums, 0, k - 1);
        rev(nums, k, n - 1);
    }
};

