static void rev(int* a, int lo, int hi) {
    while (lo < hi) { int t=a[lo]; a[lo]=a[hi]; a[hi]=t; lo++; hi--; }
}
void rotate(int* nums, int n, int k) {
    k %= n;
    rev(nums, 0, n-1);
    rev(nums, 0, k-1);
    rev(nums, k, n-1);
}
